/**
 * In-memory colour scheme manager for tests to avoid touching runtime
 * localStorage and triggering Node experimental warnings.
 */
const testColorSchemeManager = {
    get: (defaultValue: 'auto' | 'dark' | 'light') => defaultValue,
    set: () => undefined,
    subscribe: () => undefined,
